//! action-probe — gate harness for the MolmoAct2-Think vision-language-ACTION model.
//!
//! Loads a molmoact2 knot, runs the full pipeline (ViT + adapter → LM prefill →
//! autoregressive depth tokens → flow-matching action expert), and structurally
//! gates the produced robot action chunk. An action model does not emit prose, so
//! (per the "looser gate where no strict gate fits" rule) the PASS criteria are:
//!
//!   - finite: no NaN/Inf in the [horizon × action_dim] chunk
//!   - non-degenerate: overall stddev above a floor (not collapsed to a constant)
//!   - time-varying: the horizon steps are not all identical (the expert produced
//!     an actual trajectory, not one repeated pose)
//!   - bounded: |a| stays O(1) (flow output in model space, pre-unnormalization)
//!
//! Usage:
//!   action-probe --knot /path/molmoact2-think.knot \
//!     [--pixels CHW.f32] [--text-tokens 785,6722,...] [--horizon 30] [--seed 42]
//!
//! With no --pixels a deterministic SigLIP-normalized test image is synthesized;
//! with no --text-tokens a short fixed instruction token sequence is used. The
//! gate is about producing a valid action, not a specific robot command.

use std::path::PathBuf;
use std::process::exit;

use distributed_inference::model_molmoact2::MolmoAct2Pipeline;

fn die(msg: impl AsRef<str>) -> ! {
    eprintln!("action-probe: {}", msg.as_ref());
    exit(2);
}

fn main() {
    let raw: Vec<String> = std::env::args().collect();
    let mut knot: Option<PathBuf> = None;
    let mut pixels_path: Option<PathBuf> = None;
    let mut text_tokens: Vec<u32> = Vec::new();
    let mut horizon: usize = 30;
    let mut seed: u64 = 42;

    let mut i = 1;
    while i < raw.len() {
        match raw[i].as_str() {
            "--knot" => {
                i += 1;
                knot = Some(PathBuf::from(
                    raw.get(i).unwrap_or_else(|| die("--knot needs a path")),
                ));
            }
            "--pixels" => {
                i += 1;
                pixels_path = Some(PathBuf::from(
                    raw.get(i).unwrap_or_else(|| die("--pixels needs a path")),
                ));
            }
            "--text-tokens" => {
                i += 1;
                let s = raw
                    .get(i)
                    .unwrap_or_else(|| die("--text-tokens needs a CSV"));
                text_tokens = s
                    .split(',')
                    .filter(|t| !t.is_empty())
                    .map(|t| {
                        t.trim()
                            .parse::<u32>()
                            .unwrap_or_else(|e| die(format!("token {t:?}: {e}")))
                    })
                    .collect();
            }
            "--horizon" => {
                i += 1;
                horizon = raw
                    .get(i)
                    .unwrap_or_else(|| die("--horizon needs a value"))
                    .parse()
                    .unwrap_or(30);
            }
            "--seed" => {
                i += 1;
                seed = raw
                    .get(i)
                    .unwrap_or_else(|| die("--seed needs a value"))
                    .parse()
                    .unwrap_or(42);
            }
            "-h" | "--help" => {
                eprintln!("usage: action-probe --knot <path> [--pixels <chw.f32>] [--text-tokens <csv>] [--horizon N] [--seed N]");
                exit(0);
            }
            other => die(format!("unknown arg {other:?}")),
        }
        i += 1;
    }

    let knot = knot.unwrap_or_else(|| die("--knot required"));

    eprintln!("[action-probe] loading {}", knot.display());
    let t0 = std::time::Instant::now();
    let mut pipe = MolmoAct2Pipeline::load(knot.to_str().unwrap());
    eprintln!("[action-probe] loaded in {:?}", t0.elapsed());

    let img_size = pipe.config.vit_config.image_size; // 378
    let n_px = 3 * img_size * img_size;

    // Image: load CHW f32 or synthesize a deterministic SigLIP-normalized pattern.
    let pixels: Vec<f32> = match pixels_path {
        Some(p) => {
            let bytes =
                std::fs::read(&p).unwrap_or_else(|e| die(format!("read {}: {e}", p.display())));
            if bytes.len() != n_px * 4 {
                die(format!(
                    "pixels: have {} bytes, need {} ({}x{}x3 f32)",
                    bytes.len(),
                    n_px * 4,
                    img_size,
                    img_size
                ));
            }
            bytes
                .chunks_exact(4)
                .map(|c| f32::from_le_bytes([c[0], c[1], c[2], c[3]]))
                .collect()
        }
        None => {
            // Smooth gradient in [0,1] → SigLIP normalize (mean 0.5, std 0.5) → [-1,1].
            let mut v = vec![0.0f32; n_px];
            for c in 0..3 {
                for y in 0..img_size {
                    for x in 0..img_size {
                        let g = ((x + y) as f32 / (2.0 * img_size as f32) + c as f32 * 0.13) % 1.0;
                        v[c * img_size * img_size + y * img_size + x] = (g - 0.5) / 0.5;
                    }
                }
            }
            v
        }
    };

    // Prompt tokens (any valid instruction; structural gate doesn't need a specific one).
    if text_tokens.is_empty() {
        // "pick up the object" — arbitrary valid qwen-range token ids.
        text_tokens = vec![13780, 705, 279, 1633];
    }

    eprintln!(
        "[action-probe] generate_action: horizon={horizon} prompt_tokens={} seed={seed}",
        text_tokens.len()
    );
    let t1 = std::time::Instant::now();
    let action = pipe
        .generate_action(&pixels, &text_tokens, horizon, seed)
        .unwrap_or_else(|e| die(format!("generate_action failed: {e}")));
    let gen_ms = t1.elapsed().as_millis();

    let dim = pipe.config.action_expert_config.max_action_dim;
    if action.len() != horizon * dim {
        die(format!(
            "action len {} != horizon*dim {}",
            action.len(),
            horizon * dim
        ));
    }

    // ── Structural gate ────────────────────────────────────────────────────
    let finite = action.iter().all(|x| x.is_finite());
    let mean = action.iter().sum::<f32>() / action.len() as f32;
    let var = action.iter().map(|x| (x - mean).powi(2)).sum::<f32>() / action.len() as f32;
    let std = var.sqrt();
    let max_abs = action.iter().fold(0.0f32, |m, &x| m.max(x.abs()));

    // Time variation: stddev of the per-step L2 norms across the horizon.
    let step_norms: Vec<f32> = (0..horizon)
        .map(|t| {
            action[t * dim..(t + 1) * dim]
                .iter()
                .map(|x| x * x)
                .sum::<f32>()
                .sqrt()
        })
        .collect();
    let sn_mean = step_norms.iter().sum::<f32>() / horizon as f32;
    let sn_std = (step_norms
        .iter()
        .map(|x| (x - sn_mean).powi(2))
        .sum::<f32>()
        / horizon as f32)
        .sqrt();

    eprintln!("[action-probe] chunk [{horizon}x{dim}]  gen={gen_ms}ms");
    eprintln!("  finite={finite}  mean={mean:.4}  std={std:.4}  max_abs={max_abs:.4}");
    eprintln!("  per-step L2 mean={sn_mean:.4}  per-step L2 std={sn_std:.4} (time variation)");
    eprintln!("  first step: {:?}", &action[0..dim.min(8)]);
    eprintln!(
        "  last  step: {:?}",
        &action[(horizon - 1) * dim..(horizon - 1) * dim + dim.min(8)]
    );

    let pass = finite && std > 1e-3 && sn_std > 1e-4 && max_abs < 1.0e3;
    if pass {
        println!("PASS molmoact2-think action expert: valid time-varying action chunk (std={std:.3}, time_var={sn_std:.4})");
        exit(0);
    } else {
        println!(
            "FAIL molmoact2-think: finite={finite} std={std:.4} time_var={sn_std:.4} max_abs={max_abs:.2}"
        );
        exit(1);
    }
}
